<a-form ref="formRef" name="event" :model="state" :rules="formRules" layout="horizontal" labelAlign="right" :label-col="{ span: 4 }" @finish="handleFinish"><a-form-item class="mt-4" name="projectCode" label="Código de proyecto" :wrapper-col="{ span: 2 }"><a-input v-model:value="state.projectCode"></a-input></a-form-item><a-form-item name="name" label="Name"><a-input v-model:value="state.name"></a-input></a-form-item><a-form-item name="description" label="Description"><a-textarea v-model:value="state.description"></a-textarea></a-form-item><a-form-item name="projectType" label="Type" :wrapper-col="{ span: 3 }"><a-select v-model:value="state.projectType"><a-select-option :value="EVENT_TYPE.ONSITE">On-site</a-select-option><a-select-option :value="EVENT_TYPE.ONLINE">Online</a-select-option></a-select></a-form-item><a-form-item name="startDate" label="Start date" :wrapper-col="{ span: 5 }"><a-date-picker type="datetime" v-model:value="state.startDate" show-time format="DD-MM-YYYY HH:mm" value-format="YYYY-MM-DD HH:mm:ss"><a-input type="date" v-model:value="state.startDate"></a-input></a-date-picker></a-form-item><a-form-item name="finishDate" label="End date" :wrapper-col="{ span: 5 }"><a-date-picker type="datetime" v-model:value="state.finishDate" show-time format="DD-MM-YYYY HH:mm" value-format="YYYY-MM-DD HH:mm:ss"></a-date-picker></a-form-item><br><div class="flex justify-end"><a-form-item><a-button :disabled="loading" html-type="submit" type="primary">Save</a-button></a-form-item></div></a-form>