<div class="flex flex-col p-5"><p class="flex justify-start font-mono text-gray-500">The following fields have been enabled for this event. Please note that you can edit them on the “Details” tab. Click the “Download Template” button to download a CSV file:</p><div class="flex flex-col"><div class="overflow-auto mb-4 max-w-full"><a-table class="mt-5 table" :columns="state.columns"></a-table></div><a-button class="my-4 w-44" @click="handleCreateCSV">Download template</a-button></div><p class="flex justify-start font-mono text-gray-500 mt-5">Use the ‘Select File’ button to upload a CSV file containing the users you want to register:</p><input type="file" name="csv" @change="handleChange"><a-alert class="mt-5 text-center" v-if="state.error" message="Se ha producido un error. Inténtelo de nuevo más tarde" type="error"></a-alert><div v-if="state.loading"><a-alert class="mt-5 text-center" message="Procesando información..." type="info"></a-alert><a-skeleton :loading="state.loading" :active="state.loading"></a-skeleton></div><div v-if="!state.loading"><a-alert class="mt-5 text-center" v-if="state.bool" message="Los usuarios de la siguiente tabla se han registrado correctamente." type="success"></a-alert><div class="overflow-auto mb-4 max-w-full max-h-[200px]"><a-table class="mt-5" v-if="state.bool" :dataSource="state.dataSource" :columns="state.columns" style="color: green;" :scroll="{ y: 150 }"></a-table></div><a-alert class="mt-5 text-center" v-if="state.bool2" message="Los usuarios de la siguiente tabla NO se han registrado correctamente." type="error"></a-alert><div class="mb-4 max-w-full max-h-[200px]"><a-table class="mt-5" v-if="state.bool2" :dataSource="state.dataSource2" :columns="state.columns2" :pagination="false" style="color: red;" :scroll="{ y: 150 }"></a-table></div><a-button class="my-5" v-if="state.bool2" @click="handleCreateCSVBadRequest()">Download errors</a-button></div></div>